// =============================================
// PUSH NOTIFICATION - Zero dipendenze esterne
// Usa solo crypto e https (built-in Node.js)
// =============================================

const crypto = require('crypto');
const https = require('https');
const http = require('http');

// ===== VAPID CONFIG =====
const VAPID_PUBLIC_KEY = 'BAzB1_7H9MmyZGn2VeTLmfYdKHgekj3ZY7ElmD93ODlxvBChvKN-43VH-BLAepBnSMr8D3XyLua_DpS56Jp7soE';
const VAPID_PRIVATE_KEY = 'ujGxPNIepqQvKL0h6GWVjEXG4YqyxkarpIEYUU3vPeg';
const VAPID_SUBJECT = 'mailto:irenegipsytattoo@gmail.com';

// ===== HELPERS =====
function b64url(buf) {
  return Buffer.from(buf).toString('base64').replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '');
}
function b64urlDec(s) {
  s = s.replace(/-/g, '+').replace(/_/g, '/');
  while (s.length % 4) s += '=';
  return Buffer.from(s, 'base64');
}

// HKDF (RFC 5869)
function hkdf(ikm, salt, info, len) {
  const prk = crypto.createHmac('sha256', salt.length ? salt : Buffer.alloc(32)).update(ikm).digest();
  let t = Buffer.alloc(0), out = Buffer.alloc(0);
  for (let i = 1; out.length < len; i++) {
    t = crypto.createHmac('sha256', prk).update(Buffer.concat([t, info, Buffer.from([i])])).digest();
    out = Buffer.concat([out, t]);
  }
  return out.slice(0, len);
}

// VAPID JWT (ES256)
function vapidAuth(endpoint) {
  const u = new URL(endpoint);
  const aud = u.protocol + '//' + u.host;
  const hdr = b64url(JSON.stringify({ typ: 'JWT', alg: 'ES256' }));
  const pay = b64url(JSON.stringify({
    aud: aud,
    exp: Math.floor(Date.now() / 1000) + 43200,
    sub: VAPID_SUBJECT
  }));
  const unsigned = hdr + '.' + pay;

  const pub = b64urlDec(VAPID_PUBLIC_KEY);
  const key = crypto.createPrivateKey({
    key: { kty: 'EC', crv: 'P-256', x: b64url(pub.slice(1, 33)), y: b64url(pub.slice(33, 65)), d: VAPID_PRIVATE_KEY },
    format: 'jwk'
  });
  const sig = crypto.sign('sha256', Buffer.from(unsigned), { key: key, dsaEncoding: 'ieee-p1363' });
  return 'vapid t=' + unsigned + '.' + b64url(sig) + ', k=' + VAPID_PUBLIC_KEY;
}

// Web Push Encryption (RFC 8291 + RFC 8188)
function encrypt(p256dh, auth, text) {
  const uaPub = b64urlDec(p256dh);
  const uaAuth = b64urlDec(auth);
  const ec = crypto.createECDH('prime256v1');
  ec.generateKeys();
  const asPub = ec.getPublicKey();
  const secret = ec.computeSecret(uaPub);

  const ikm = hkdf(secret, uaAuth, Buffer.concat([Buffer.from('WebPush: info\0'), uaPub, asPub]), 32);
  const salt = crypto.randomBytes(16);
  const cek = hkdf(ikm, salt, Buffer.from('Content-Encoding: aes128gcm\0'), 16);
  const nonce = hkdf(ikm, salt, Buffer.from('Content-Encoding: nonce\0'), 12);

  const c = crypto.createCipheriv('aes-128-gcm', cek, nonce);
  const enc = Buffer.concat([c.update(Buffer.concat([Buffer.from(text), Buffer.from([2])])), c.final(), c.getAuthTag()]);

  const rs = Buffer.alloc(4);
  rs.writeUInt32BE(4096);
  return Buffer.concat([salt, rs, Buffer.from([65]), asPub, enc]);
}

// HTTP POST to push service
function sendPush(endpoint, p256dh, auth, text) {
  return new Promise((resolve, reject) => {
    const body = encrypt(p256dh, auth, text);
    const u = new URL(endpoint);
    const opts = {
      hostname: u.hostname,
      port: u.port || 443,
      path: u.pathname + u.search,
      method: 'POST',
      headers: {
        'Content-Type': 'application/octet-stream',
        'Content-Encoding': 'aes128gcm',
        'Content-Length': body.length,
        'Authorization': vapidAuth(endpoint),
        'TTL': '86400',
        'Urgency': 'normal'
      }
    };
    const transport = u.protocol === 'https:' ? https : http;
    const req = transport.request(opts, (res) => {
      let d = '';
      res.on('data', (chunk) => d += chunk);
      res.on('end', () => resolve({ statusCode: res.statusCode, body: d }));
    });
    req.on('error', (e) => reject(e));
    req.write(body);
    req.end();
  });
}

// ===== MAIN =====
const items = $input.all();
let subs;
if (items.length === 1 && Array.isArray(items[0].json)) {
  subs = items[0].json;
} else {
  subs = items.map(i => i.json);
}

const wb = $('Webhook Trigger').first().json.body;
const payload = JSON.stringify({
  title: wb.title || 'Irene Gipsy Tattoo',
  body: wb.message || '',
  icon: '/icons/icon-192x192.png',
  url: wb.url || '/dashboard.html',
  tag: wb.tag || 'igt-' + Date.now(),
  type: wb.type || 'general'
});

const results = [];
for (const sub of subs) {
  if (!sub.endpoint) continue;
  try {
    const r = await sendPush(sub.endpoint, sub.p256dh, sub.auth, payload);
    if (r.statusCode >= 200 && r.statusCode < 300) {
      results.push({ endpoint: sub.endpoint, status: 'sent' });
    } else if (r.statusCode === 410 || r.statusCode === 404) {
      results.push({ endpoint: sub.endpoint, status: 'expired', code: r.statusCode });
    } else {
      results.push({ endpoint: sub.endpoint, status: 'error', code: r.statusCode, body: r.body });
    }
  } catch (e) {
    results.push({ endpoint: sub.endpoint, status: 'error', error: e.message });
  }
}

return [{
  json: {
    sent: results.filter(r => r.status === 'sent').length,
    expired: results.filter(r => r.status === 'expired').length,
    total: subs.length,
    results: results
  }
}];
